{
  "summary": "This paper presents CORA, a unified multilingual open question answering system that integrates cross-lingual dense passage retrieval and multilingual answer generation. Through iterative training with cross-lingual data expansion leveraging Wikipedia language links and model predictions, CORA achieves state-of-the-art results on challenging multilingual QA benchmarks across 26 languages, including unseen languages, without relying on external translation components.",
  "strengths": [
    {
      "point": "Unified multilingual open QA model without reliance on external translation",
      "evidence": "CORA integrates cross-lingual dense passage retrieval and multilingual answer generation into a single model that retrieves and generates answers in multiple languages without language-specific translation or retrieval modules."
    },
    {
      "point": "Novel iterative training with cross-lingual data expansion",
      "evidence": "The iterative procedure uses Wikipedia language links and model predictions to expand training data, improving retrieval and generation performance especially for low-resource and unseen languages without additional human annotation or machine translation."
    },
    {
      "point": "Strong empirical performance across diverse languages",
      "evidence": "CORA outperforms previous state-of-the-art by large margins on XOR-TYDI QA and MKQA datasets, achieving gains of 21.4 and 4.9 F1 points respectively, and shows improvements on 9 unseen languages."
    },
    {
      "point": "Comprehensive analysis and insights",
      "evidence": "The paper provides detailed analysis showing the importance of cross-lingual retrieval, human evaluation of passage relevance, and error analysis highlighting retrieval errors and generation language issues."
    }
  ],
  "weaknesses": [
    {
      "point": "Insufficient comparison to recent multilingual dense retrieval models",
      "evidence": "The paper does not compare CORA's mDPR against recent strong multilingual dense retrieval baselines like mContriever or multilingual ColBERT variants, weakening the novelty claim of the retrieval component."
    },
    {
      "point": "Lack of justification for choice of pretrained models",
      "evidence": "No discussion or ablation is provided to justify using mBERT for retrieval and mT5 for generation over other multilingual pretrained models such as XLM-R or mBART."
    },
    {
      "point": "Limited ablation studies on iterative training components",
      "evidence": "Ablations do not isolate the impact of individual components like Wikipedia language links versus model-predicted passage labeling, limiting understanding of which parts drive performance gains."
    },
    {
      "point": "Evaluation baselines may not be fully competitive",
      "evidence": "The paper lacks comparisons to strong recent multilingual retrieval+generation baselines trained end-to-end, raising concerns about whether gains stem from the unified model or stronger training/data."
    },
    {
      "point": "Evaluation metrics limited and missing human evaluation of generated answers",
      "evidence": "Evaluation relies heavily on F1 scores and human evaluation of passage relevance, but does not assess answer correctness, fluency, or language quality through human judgments."
    },
    {
      "point": "Reproducibility details missing",
      "evidence": "Key training hyperparameters, hardware details, retrieval index construction, and size are not described, hindering reproducibility of the iterative training and retrieval setup."
    },
    {
      "point": "Clarity issues in method description",
      "evidence": "Ambiguities remain about how language tags are used during training and inference, and the cross-lingual data expansion process lacks concrete examples or pseudocode."
    },
    {
      "point": "Limitations not fully addressed",
      "evidence": "The paper does not discuss handling code-switching or mixed-language inputs, nor does it propose solutions for generation errors producing answers in the wrong language."
    },
    {
      "point": "Generalisability and scalability concerns",
      "evidence": "Evaluation is limited to Wikipedia-based datasets and 26 languages; scalability to larger corpora or hundreds of languages and performance on non-Wikipedia domains are not discussed."
    },
    {
      "point": "No analysis linking retrieval errors to QA performance",
      "evidence": "Although retrieval errors are noted as dominant, there is no detailed quantitative analysis connecting retrieval failure modes to answer generation errors or overall QA degradation."
    },
    {
      "point": "Lack of cross-domain or cross-task evaluation",
      "evidence": "The approach is only evaluated on open-domain QA without exploring applicability to related tasks like fact verification or closed-book QA."
    }
  ],
  "questions": [
    {
      "question": "How does CORA's mDPR compare quantitatively to recent multilingual dense retrieval models like mContriever or multilingual ColBERT?",
      "motivation": "Understanding this comparison is critical to assess the novelty and effectiveness of the retrieval component relative to the current state-of-the-art."
    },
    {
      "question": "What is the impact of using different multilingual pretrained models (e.g., XLM-R, mBART) for retrieval and generation compared to mBERT and mT5?",
      "motivation": "Model choice can significantly affect cross-lingual transfer and generation quality; ablations would clarify whether CORA's design choices are optimal."
    },
    {
      "question": "Can the iterative training procedure be detailed with concrete examples or pseudocode to improve clarity and reproducibility?",
      "motivation": "Clear understanding of the data expansion process is essential for replicating and building upon this work."
    },
    {
      "question": "How does CORA perform on non-Wikipedia corpora or domains with less aligned multilingual content?",
      "motivation": "Evaluating generalizability beyond Wikipedia is important for real-world applicability."
    },
    {
      "question": "What strategies could mitigate generation errors producing answers in the wrong language?",
      "motivation": "Addressing this limitation is crucial for practical deployment in multilingual settings."
    },
    {
      "question": "How scalable is CORA in terms of computational resources and retrieval latency when extending to hundreds of languages or larger document collections?",
      "motivation": "Scalability considerations affect the feasibility of deploying CORA in large-scale multilingual environments."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
